var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"진짜 하라고?","JPN":"本当にやれって？","ENG":"Seriously?","TWN":"確定？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"싫으면 계속 여기 남아있어라.","JPN":"嫌ならずっとここにいろ。","ENG":"You can stay here if you want.","TWN":"不願意就繼續留在這裡。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그것도 아니면 자력으로 탈출하던지.","JPN":"それか、自力で脱出するんだな。","ENG":"Or escape on your own.","TWN":"或者自己逃出去。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아, 알겠어. 하면 될 거 아냐!","JPN":"わ、わかったよ！　やればいいんでしょ！","ENG":"Ugh, fine. I'll do it!","TWN":"唉，知道了。做就做！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"A-4동의 방어설비 70%가 무력화됐습니다.","JPN":"A-4棟の防御設備の70％が無力化されました。","ENG":"70% of the defense system in section A-4 has been disabled.","TWN":"A-4號樓70%的防禦系統已經失效。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"지금이라도 결정을 내리셔야 합니다.","JPN":"今からでも決断すべきです。","ENG":"You need to make a decision, now.","TWN":"你現在必須做出決定。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"어쩔 수 없군.","JPN":"仕方ない。","ENG":"It can't be helped.","TWN":"沒辦法了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"헤이븐이 인질로 잡혀 있긴 하지만… 이대로 뒀다간 침입자 하나 때문에 아케론 전체가 위험해진다.","JPN":"ヘイブンが人質になっているが……このままでは侵入者一人のせいでアケロン全体が危険だ。","ENG":"Haven is held as hostage, but... all of Acheron will be in danger because of one intruder if we don't act.","TWN":"雖然天堂被劫持為人質……但這樣下去整個黃泉都會因為一個入侵者陷入危機。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"엔지니어! A-4동을 즉시 큐브에서 사출을…!","JPN":"エンジニア！　A-4棟を直ちにキューブから射出……！","ENG":"Engineer! Detach and launch section A-4 from the Cube...!","TWN":"工程師！立即將A-4號從魔方分離……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"잠시만요!","JPN":"お待ち下さい！","ENG":"Wait!","TWN":"等一下！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"방금 23번 카메라에 3명의 움직임이 잡혔습니다!","JPN":"先ほど23番カメラで3人の動きを捉えました！","ENG":"We just caught three people moving on camera 23!","TWN":"23號監視器剛剛捕捉到三個人！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"3명이라고?","JPN":"3人だと？","ENG":"Three?","TWN":"三個人？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"그런데… 죄수 한 명이 이쪽 카메라에 대고 뭔가 말하고 있는데요?","JPN":"ところで……囚人の一人がこちらのカメラに向かって何か言っています。","ENG":"But... one of the prisoners is saying something to the camera.","TWN":"但是……有一個囚犯正在對著這邊的鏡頭說話？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"대체… 무슨 상황이 벌어지고 있는 거야?","JPN":"いったい……何が起きてるんだ？","ENG":"What... is happening?","TWN":"這到底……怎麼回事？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 아저씨들-","JPN":"おーい、おっさんたち～！","ENG":"Hey, fellas.","TWN":"嘿——"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"설마 선량하고 무고한 인간들을 우주 멀리 날려버릴 생각은 아니겠지?","JPN":"まさか善良で無実の人間を、遠い宇宙に飛ばすつもりじゃないよね？","ENG":"You wouldn't want to send these kind, innocent people out into space, would you?","TWN":"你該不會把無辜的好人扔到遙遠的太空吧？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"테러리스트! 네가 어떻게 바깥으로 나온 거지? 그 자들과 한 패거리였나?","JPN":"テロリスト！　なぜお前が外にいる！　あの者たちとグルだったのか？","ENG":"You terrorist! How did you escape? Are you working with them?","TWN":"恐怖分子！你是怎麼出來的？你和他們是一夥的嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"한 패거리? 난 누굴 이용해먹었으면 이용했지, 쉽게 편 먹는 스타일은 아닌데?","JPN":"グル？　あたしは誰かを利用するタイプなの。そんな簡単に味方になんかならないよ。","ENG":"Working with them? I prefer to use people than to team up with them.","TWN":"一夥？我只會利用別人，並不會輕易和別人成為同夥喔？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"네가 있는 곳에 침입한 건 코핀 컴퍼니의 힐데 소대장뿐이었다. 널 도와줄 수 있는 것도 그 자 밖에 없어.","JPN":"そこに侵入したのは、コフィンカンパニーのヒルデ小隊長だけだった。お前を監獄から助けられるのもあの者しかいない。","ENG":"Commander Hilde of Coffin Company is the only one who infiltrated in that area. She was the only one who could've helped you.","TWN":"入侵你所在的地區之人只有科芬公司的希爾德小隊長。能幫助你的也只有她了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"힐데…?","JPN":"ヒルデ……？","ENG":"Hilde...?","TWN":"希爾德……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아- 내가 데려온 이 녀석?","JPN":"あー、あたしが連れてきたこいつ？","ENG":"Oh, you mean her? I brought her here.","TWN":"啊……是指我帶來的這個人？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"네가… 데려온 거라고…?","JPN":"お前が……連れてきた……？","ENG":"You... brought her?","TWN":"你帶來的……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아하하, 그 잘난 태스크포스 나리께서 테러리스트인 날 구해주러 올 리 없잖아?","JPN":"あはは、あのお偉いタスクフォースがテロリストのあたしを助けに来るわけないだろ？","ENG":"Ah ha ha. That haughty TASKFORCE leader would never come to save a terrorist like me.","TWN":"啊哈哈，自以為是的特遣勢力怎麼會救出我這個恐怖分子呢？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"실은 내가 아케론에 수감되기 전에 이 여자한테 암시를 걸어 뒀거든.","JPN":"実はあたしがアケロンに収監される前、この女に暗示をかけておいたんだよ。","ENG":"I actually mind-controlled her before I was sent to Acheron.","TWN":"其實我在被關進黃泉之前給這個女人留下了提示。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"신분을 속이고 이곳까지 잠입해서 날 탈옥할 수 있게 도와달라고 말이야.","JPN":"身元を偽装しここに侵入したら、あたしの脱獄を助けてくれってね。","ENG":"I made it so that she'd fake her identity, infiltrate, and break me out.","TWN":"我讓她偽裝身分潛入這裡，幫助我越獄逃出去。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"암시라고?! 그런 게 정말 실제로 가능하단 말인가?","JPN":"暗示だと！？　本当にそんなことができるのか？","ENG":"Mind control?! Is that really possible?!","TWN":"提示？！真的能做到這種事情？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"보세요! 저 범죄자에겐 세뇌 능력이 있을 거라고 제가 말했잖습니까!","JPN":"ほら！　あの犯罪者には洗脳の能力があると言ってたじゃないですか！","ENG":"Look! I told you that criminal had brainwashing abilities!","TWN":"你看！我說過那個囚犯擁有洗腦的能力！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"테러 현장마다 목격자가 없다는 것도 사람들의 기억을 조작한 게 틀림없어요!","JPN":"どのテロ現場にも目撃者がいなかったのも、人々の記憶を捏造したからに違いありません！","ENG":"There was no witness in every area she terrorized! She must've manipulated the witnesses' memories!","TWN":"每個恐怖襲擊地點都沒有目擊者，這表示人們的記憶肯定被她篡改了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"어쩐지 붙잡혀온 죄수치곤 여유롭더라니, 탈옥은 처음부터 계획되어 있었던 건가!","JPN":"囚人にしては余裕があると思ったら、最初から脱獄する計画だったのか！","ENG":"I thought she was too relaxed for a convicted felon. She was planning to escape all along!","TWN":"怪不得看起來從容不迫，原來早就想好了越獄計畫！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Hmm...","TWN":"唔……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐어, 너희가 추측하는 것들은 대충 전부 맞다고 보면 돼.","JPN":"まあ、そんなところかな。","ENG":"Well, all of your assumptions are basically correct.","TWN":"你們的猜測基本都是正確的。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아무튼 이해했지? 이 무고한 인질 둘을 희생시키고 싶지 않다면, 앞으로 내 요구에 순순히 응해야 할…","JPN":"とにかく、わかったでしょ？　この何の罪もない人質二人を犠牲にしたくなければ、これからあたしの要求に素直に従って……","ENG":"Anyway, you got it? If you don't want to sacrifice these two innocents, you're going to do what I say–","TWN":"總之明白了嗎？ 如果你不想犧牲這兩個無辜的人質，就必須遵守我的要求……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"수감동을 분리해라!","JPN":"収容棟を分離しろ！","ENG":"Detach the section!","TWN":"分離牢房！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"어떤 희생이 있더라도 저런 괴물이 절대 이쪽으로 넘어오게 해선 안 돼!","JPN":"どんな犠牲があろうと、あんな化け物がこちら側に来ることは絶対にあってはならない！","ENG":"Do whatever it takes to keep that monster from coming to this side!","TWN":"無論如何都不能讓那個怪物來到這裡！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭣? 야, 잠깐…!","JPN":"は？　ねえ、ちょっと……！","ENG":"Huh? W-wait...!","TWN":"什麼？等一下……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이 자식들… 진짜로 분리했잖아?","JPN":"あいつら……マジで分離しやがった！","ENG":"Those bastards... They really detached the section.","TWN":"這些混蛋……竟然真的分離了？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 겁을 너무 준 모양이군.","JPN":"どうやら脅しが効きすぎたようだな。","ENG":"I guess you scared them too much.","TWN":"剛才好像說得有點超過。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"난 그쪽이 시킨대로 했을 뿐이거든?","JPN":"あたしはあんたの言うとおりにしただけだよ？","ENG":"I just did what you told me to, okay?","TWN":"我只是按你說的去做而已！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"목표는 달성했다. 이젠 내가 뭘 하더라도 녀석들에겐 네가 세뇌한 탓이라고 둘러댈 수 있으니까.","JPN":"だが目的は達成した。これから私が何をしようと、あいつらにはお前に洗脳されたと言えばいい。","ENG":"We still achieved the goal. Now I can use your brainwashing ability as an excuse for whatever I do.","TWN":"目標已經達成了。以後不管做什麼都能把責任歸咎於你的洗腦。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"하지만 그게 무슨 소용이죠? 아케론 큐브에서 분리된 이상 돌아갈 방법이 없잖아요.","JPN":"でも、それが何の役に立つんですか？　アケロンキューブから分離された以上、帰る方法はありませんよ。","ENG":"But how will that help? We've been detached from the Acheron Cube, and there's no way to return.","TWN":"但這有什麼用呢？ 一旦你從黃泉魔方分離就再也回不去了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"CRF라는 건 사용자의 의지에 따라 그 활용도가 무궁무진하다.","JPN":"CRFというものは、使用者の意志によってその活用度に限りはない。","ENG":"CRF can be utilized in countless different ways depending on the wielder's will.","TWN":"CRF會根據使用者的意圖發揮出無窮無盡的用途。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가령 충격에너지를 한 곳에 집중시킨다거나 말이지.","JPN":"例えば、衝撃エネルギーを一か所に集中させるとか、な。","ENG":"For example, the force of impact can be concentrated at one point in space.","TWN":"例如將衝擊能量集中在一處"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"예…?","JPN":"はい……？","ENG":"Pardon...?","TWN":"啊……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"뭐하는 겁니까?","JPN":"何してるんですか？","ENG":"What are you doing?","TWN":"你在幹什麼？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그렇게 발로 차도 큐브의 외벽은 부술 수 없습니다! 함선보다 두껍다고요!","JPN":"蹴ったってキューブの外壁は破壊できません！　艦船より厚いんですよ！","ENG":"Kicking it won't break the Cube's outer walls! It's thicker than a ship!","TWN":"魔方的外壁是踢不壞的！它比艦船還要厚！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그거 잘 됐군.","JPN":"それはよかった。","ENG":"That's good news.","TWN":"好極了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니, 외벽이 부서지면 우린 전부 끝장이라니까. 전부 죽을 셈이야?","JPN":"いや、外壁が壊れたらあたしたちこの場で終わりなんだって。みんなで死ぬ気？","ENG":"Wait, we're all done for if you break the outer walls. Are you trying to kill all of us?","TWN":"不不，要是外壁被破壞，我們就全完了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇다고 여기서 가만히 있어 봐야…","JPN":"だが、ここでじっとしていたところで……","ENG":"Staying still in outer space...","TWN":"但就這樣乾等也不是辦法……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"끝장이나는 건 마찬가지지 않나?","JPN":"終わるのは同じではないか？","ENG":"Won't change anything.","TWN":"不管怎樣不都是死路一條嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그렇다고 공기도 없는 우주에서 질식사할 생각은 없거든?","JPN":"でもあたし、宇宙で窒息死するなんてごめんなんだけど？","ENG":"I'd still rather not suffocate in oxygen-less space.","TWN":"就算這樣也不想在太空裡窒息死好不好？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"무식한 짓은 멈추고 생각이라도 좀…!","JPN":"バカげたことやめて、ちょっと考え……！","ENG":"Quit your reckless kicking and think...!","TWN":"別亂動了，快想想辦法……！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"에이미 양.","JPN":"エイミーさん。","ENG":"Amy.","TWN":"艾米。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"창 밖을 좀 보세요…","JPN":"窓の外を見てください……","ENG":"Look outside the window...","TWN":"看看窗外……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"Huh...?","TWN":"什麼……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"휴우, 이걸로 문제는 일단락인가?","JPN":"ふう、これで問題は一段落ついたか？","ENG":"Phew. Guess we got rid of that problem.","TWN":"呼，這樣的話問題應該算是解決了吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"현명한 판단을 내리셨습니다, 소장님.","JPN":"賢明なご判断です、所長。","ENG":"That was a wise decision, sir.","TWN":"你做了一個明智的決定，典獄長。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"그런 위험 인물이 풀려나 아케론 전체에 어떤 악영향을 끼칠지 모르는 상황에서, 누군가는 그런 결정을 내려야 했을 겁니다.","JPN":"あのような危険人物が野放しになれば、アケロンにどんな影響を及ぼすか計り知れません。誰でも同じ判断を迫られたでしょう。","ENG":"Someone had to make the call since she could've wreaked havoc on all of Acheron after breaking free.","TWN":"那種危險人物會對整個黃泉造成極壞的影響，必須有人站出來做出決斷。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"…그렇겠지.","JPN":"……だろうな。","ENG":"...Right.","TWN":"……確實。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"하지만 헤이븐마저 엮이게 된 건 유감이야.","JPN":"だが、ヘイブンを失ったのは残念だ。","ENG":"But it's a shame Haven was caught up in it.","TWN":"但是很遺憾連天堂也捲入進來了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"적어도 힉스가 여기 있었더라면 녀석을 살릴만한 방법을 시도해봤을 텐데…","JPN":"ヒックスがここにいれば、奴を助けられたかもしれないのに……","ENG":"We might've been possible to save him if Hicks were here...","TWN":"如果希克思在場的話，或許能嘗試一些救出他的辦法。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"어… 소장님?","JPN":"あれ？　……所長。","ENG":"Uh... Sir?","TWN":"呃……典獄長？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"방금 저희가 사출시킨 A-4동의 신호가 다시 잡히고 있습니다.","JPN":"さっき射出したA-4棟の信号を再度受信しました。","ENG":"We're getting signals from section A-4, the one we just launched into space.","TWN":"剛剛又捕捉到了已經被分離的A-4號的訊號。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"게다가… 점점 가까워지고 있어요.","JPN":"しかも……どんどんこちらに近づいてきてます。","ENG":"And it's... getting closer.","TWN":"而且……訊號越來越近了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"뭐? 가까워진다는 게 무슨 소리지?","JPN":"何？　どういうことだ？","ENG":"What? What do you mean it's getting closer?","TWN":"嗯？什麼叫越來越近？"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"그건 불가능합니다. 아케론의 수감동에는 그런 식으로 돌아올 수 있는 추진기관이 전혀 존재하지 않아요.","JPN":"そんな……ありえません。アケロンの収容棟に帰還機能は備わっていません。","ENG":"That's impossible. Acheron's prison sections don't have any sort of propulsion unit that can bring them back here.","TWN":"這不可能。黃泉的牢房根本就沒有這種用於返回的推進器。"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"카메라에 정거장이 잡힙니다! 이대로라면 아케론 수송포트까지 진입할 겁니다!","JPN":"カメラにステーションが見えます！　このままだと、アケロン輸送ポートまで進入します！","ENG":"I can see the space station through the camera! We're going to enter Acheron's transfer port!","TWN":"鏡頭裡看到了太空站！這樣下去就能進入黃泉輸送埠了！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하하… 하… 이런 게 진짜로 되는 거야?","JPN":"はは……は……まさか本当にやってのけるとは……","ENG":"Haha... ha... How is this really happening?","TWN":"哈哈……哈哈……真的做到了？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그러게요. 우주를 이런 식으로 날 수 있다니…","JPN":"そうですね。これで宇宙が飛べるなんて……","ENG":"I know, right? To fly through space like this...","TWN":"是啊，我真不敢相信能以這種方式在太空中飛行……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"엄청 신기하군요!","JPN":"不思議ですね！","ENG":"It's fascinating!","TWN":"太神奇了！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…살다 살다 이런 말을 내가 하게 될 줄은 몰랐는데.","JPN":"……こんなこと一生言うことないと思ってたけどさ。","ENG":"...I didn't think the day would come for me to say this.","TWN":"……沒想到自己會說出這種話。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"당신들 둘 다 제정신이 아니야.","JPN":"あんたら二人とも、正気じゃないね。","ENG":"But you're both out of your minds.","TWN":"你們兩個都瘋了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_BOSS","text":{"KOREA":"사출했던 아케론 큐브가 돌아온다! 방호막을 전개해!","JPN":"射出したアケロンキューブが戻ってくる！　シールドを展開しろ！","ENG":"The detached Acheron Cube is returning! Activate the force shields!","TWN":"彈出的黃泉魔方回來了！展開防護網！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"접근 속도가 너무 빠릅니다! 충격을 상쇄하기엔 시간이 부족해요!","JPN":"接近速度が速すぎます！　衝撃を相殺するには時間が足りません！","ENG":"It's approaching too fast! We don't have enough time to offset the impact!","TWN":"接近速度太快！沒有足夠的時間來抵消衝擊！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"다들! 충격에 대비하세요!","JPN":"みなさん！　衝撃に備えてください！","ENG":"Everyone! Brace for impact!","TWN":"要來了！大家準備好！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그런데…","JPN":"ところで……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"이건 너무 빠르지 않나요?!","JPN":"ちょっと速すぎませんか！？","ENG":"Isn't this way too fast?!","TWN":"這是不是太快了？！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐라도 붙잡아!","JPN":"なんでもいいから掴まれ！","ENG":"Hold on to something!","TWN":"快抓穩！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};